styles.chat_sidebar.folder_button:
QPushButton {
 background-color:transparent;
 border:none;
 border-radius:0;
 padding:0;
 color:#dfe6f0;
 outline:none;
}
QPushButton:hover { background-color:rgba(118,140,158,0.15); }
QPushButton:checked {
 background-color:rgba(89,183,233,0.18);
 border-color:rgba(89,183,233,0.55);
}
QPushButton QLabel { background:transparent; }

styles.chat_sidebar.list:
QListWidget{font-size:13px; background-color:#17212b; border:1px solid #2a2a2a; padding:0; margin:0; outline:none;}
QListWidget::item{height:${row_height}px; padding:0; margin:0; color:#e0e0e0;}
QListWidget::item:selected{background-color:#2f4f6f; color:#ffffff; border:none;}
QListWidget::item:hover{background-color:#202a36;}
QListWidget::item:focus{outline:none;}

styles.settings.action_button:
QPushButton {
 text-align:left;
 padding:10px;
 border-radius:8px;
 background-color:rgba(255,255,255,0.02);
 color:#dfe6f0;
}
QPushButton:hover { background-color:rgba(89,183,233,0.18); }
QPushButton:pressed { background-color:rgba(89,183,233,0.28); }

styles.settings.tabs:
QTabWidget::pane { background-color:#0c141e; border:1px solid rgba(255,255,255,0.08); border-radius:10px; }
QTabBar::tab { background-color:rgba(255,255,255,0.04); color:#dfe6f0; padding:8px 16px; border-top-left-radius:8px; border-top-right-radius:8px; margin-right:2px; }
QTabBar::tab:selected { background-color:rgba(89,183,233,0.26); }
QTabBar::tab:hover { background-color:rgba(89,183,233,0.14); }

styles.style_editor.group:
QGroupBox { background-color:#101923; border:1px solid rgba(255,255,255,0.08); border-radius:10px; margin-top:12px; }
QGroupBox::title { color:#dfe6f0; subcontrol-origin: margin; left:14px; padding:0 6px; font-weight:600; }
#StyleQuickLabel { font-size:12px; color:#9fb0c4; }
#StyleMetricLabel { min-width:48px; text-align:right; font-weight:600; color:#dfe6f0; }

styles.style_editor.tree:
QTreeWidget { background-color:#0b121c; border:1px solid rgba(255,255,255,0.08); padding:2px; }
QTreeWidget::item { height:22px; }
QHeaderView::section { background-color:#111b27; color:#9fb0c4; border:none; padding:4px 6px; }

